#include<bits/stdc++.h>
using namespace std;
long long a[1000010];
int main()
{
    long long n,m,max1=0,sum=0;
    scanf("%lld%*lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        max1=max(max1,a[i]);
        sum+=a[i];
    }
    if(max1>=m)
    {
        sum=0;
        for(long long i=1;i<=n;i++)
        {
            sum+=max(0ll,m-a[i])+(a[i]<m);
        }
        printf("%lld",sum);
        return 0;
    }
    printf("%lld",(n+1)*(m+1)-2-max1-sum);
    return 0;
}
